```typescript
function solve(nums: number[]): number {
    const n = nums.length;
    const prefix: number[] = new Array(n);
    if (n > 0) prefix[0] = nums[0];
    for (let i = 1; i < n; i++) {
        prefix[i] = prefix[i - 1] + nums[i];
    }

    const padded: number[] = new Array(n + 1);
    padded[0] = 0;
    for (let i = 0; i < n; i++) {
        padded[i + 1] = prefix[i];
    }

    const left_start: number[] = new Array(n);
    left_start[0] = 0;
    for (let i = 1; i < n; i++) {
        if (nums[i - 1] < nums[i]) {
            left_start[i] = left_start[i - 1];
        } else {
            left_start[i] = i;
        }
    }

    const dec_end: number[] = new Array(n);
    dec_end[n - 1] = n - 1;
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] > nums[i + 1]) {
            dec_end[i] = dec_end[i + 1];
        } else {
            dec_end[i] = i;
        }
    }

    const right_end: number[] = new Array(n);
    right_end[n - 1] = n - 1;
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            right_end[i] = right_end[i + 1];
        } else {
            right_end[i] = i;
        }
    }

    class SparseTable {
        st: number[][];
        log: number[];
        n: number;
        combine: (a: number, b: number) => number;

        constructor(arr: number[], combine: (a: number, b: number) => number) {
            this.n = arr.length;
            this.combine = combine;
            this.log = new Array(this.n + 1).fill(0);
            for (let i = 2; i <= this.n; i++) {
                this.log[i] = this.log[Math.floor(i / 2)] + 1;
            }
            const k = this.log[this.n] + 1;
            this.st = Array.from({ length: k }, () => Array(this.n));
            for (let i = 0; i < this.n; i++) {
                this.st[0][i] = arr[i];
            }
            for (let j = 1; j < k; j++) {
                for (let i = 0; i + (1 << j) <= this.n; i++) {
                    this.st[j][i] = this.combine(this.st[j - 1][i], this.st[j - 1][i + (1 << (j - 1))]);
                }
            }
        }

        query(l: number, r: number): number {
            if (l > r) {
                return 0;
            }
            const len = r - l + 1;
            const j = this.log[len];
            return this.combine(this.st[j][l], this.st[j][r - (1 << j) + 1]);
        }
    }

    const min_rmq_padded = new SparseTable(padded, Math.min);
    const max_rmq_orig = new SparseTable(prefix, Math.max);

    let ans = -Infinity;

    for (let p = 1; p < n - 1; p++) {
        if (nums[p - 1] < nums[p] && nums[p] > nums[p + 1]) {
            const q = dec_end[p];
            if (q >= n - 1) continue;
            if (nums[q] >= nums[q + 1]) continue;

            const lmin = left_start[p];
            if (lmin > p - 1) continue;
            const a = lmin - 1;
            const b = p - 2;
            const min_val = min_rmq_padded.query(a + 1, b + 1);

            const r_start = q + 1;
            const r_end = right_end[q];
            if (r_start > r_end) continue;
            const max_val = max_rmq_orig.query(r_start, r_end);
            const candidate = max_val - min_val;
            if (candidate > ans) {
                ans = candidate;
            }
        }
    }

    return ans;
}
