function solve(nums: number[]): number {
    const n = nums.length;
    if (n < 4) {
        return 0;
    }
    let P = new Array(n+1).fill(0);
    for (let i = 1; i <= n; i++) {
        P[i] = P[i-1] + nums[i-1];
    }

    let L = new Array(n);
    let D = new Array(n);
    let R = new Array(n);
    L[0] = 0;
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i-1]) {
            L[i] = L[i-1];
        } else {
            L[i] = i;
        }
    }

    D[n-1] = n-1;
    for (let i = n-2; i>=0; i--) {
        if (nums[i] > nums[i+1]) {
            D[i] = D[i+1];
        } else {
            D[i] = i;
        }
    }

    R[n-1] = n-1;
    for (let i = n-2; i>=0; i--) {
        if (nums[i] < nums[i+1]) {
            R[i] = R[i+1];
        } else {
            R[i] = i;
        }
    }

    const maxLen = n+1;
    let log_arr = new Array(maxLen+1).fill(0);
    log_arr[1] = 0;
    for (let i = 2; i <= maxLen; i++) {
        log_arr[i] = log_arr[Math.floor(i/2)] + 1;
    }

    const k = log_arr[maxLen] + 1;
    let st_min = new Array(n+1);
    let st_max = new Array(n+1);
    for (let i = 0; i <= n; i++) {
        st_min[i] = new Array(k).fill(0);
        st_max[i] = new Array(k).fill(0);
    }

    for (let i = 0; i <= n; i++) {
        st_min[i][0] = P[i];
        st_max[i][0] = P[i];
    }

    for (let j = 1; j < k; j++) {
        for (let i = 0; i + (1<<j) <= n+1; i++) {
            st_min[i][j] = Math.min(st_min[i][j-1], st_min[i + (1<<(j-1))][j-1]);
            st_max[i][j] = Math.max(st_max[i][j-1], st_max[i + (1<<(j-1))][j-1]);
        }
    }

    const rmq_min = (l: number, r: number): number => {
        if (l > r) return Number.MAX_SAFE_INTEGER;
        let j = log_arr[r-l+1];
        return Math.min(st_min[l][j], st_min[r - (1<<j) + 1][j]);
    };

    const rmq_max = (l: number, r: number): number => {
        if (l > r) return Number.MIN_SAFE_INTEGER;
        let j = log_arr[r-l+1];
        return Math.max(st_max[l][j], st_max[r - (1<<j) + 1][j]);
    };

    let min_prefix_at_p = new Array(n).fill(Number.MAX_SAFE_INTEGER);
    for (let p = 1; p < n; p++) {
        let start = L[p];
        let end = p-1;
        if (start <= end) {
            min_prefix_at_p[p] = rmq_min(start, end);
        }
    }

    let max_prefix_at_q = new Array(n).fill(Number.MIN_SAFE_INTEGER);
    for (let q = 0; q < n; q++) {
        if (R[q] >= q+1) {
            let k_start = q+2;
            let k_end = R[q] + 1;
            if (k_start <= k_end) {
                max_prefix_at_q[q] = rmq_max(k_start, k_end);
            }
        }
    }

    const k2 = log_arr[n] + 1;
    let st_M = new Array(n);
    for (let i = 0; i < n; i++) {
        st_M[i] = new Array(k2).fill(Number.MIN_SAFE_INTEGER);
    }

    for (let i = 0; i < n; i++) {
        st_M[i][0] = max_prefix_at_q[i];
    }

    for (let j = 1; j < k2; j++) {
        for (let i = 0; i + (1 << j) <= n; i++) {
            st_M[i][j] = Math.max(st_M[i][j-1], st_M[i+(1<<(j-1))][j-1]);
        }
    }

    const query_M = (l: number, r: number): number => {
        if (l > r) return Number.MIN_SAFE_INTEGER;
        let len = r - l + 1;
        let j = log_arr[len];
        return Math.max(st_M[l][j], st_M[r - (1<<j) + 1][j]);
    };

    let ans = Number.MIN_SAFE_INTEGER;
    for (let p = 1; p <= n-3; p++) {
        if (min_prefix_at_p[p] === Number.MAX_SAFE_INTEGER) continue;

        let q_start = p+1;
        let q_end = Math.min(D[p], n-2);
        if (q_end < q_start) continue;

        let max_val_in_M = query_M(q_start, q_end);
        if (max_val_in_M === Number.MIN_SAFE_INTEGER) continue;

        let candidate = max_val_in_M - min_prefix_at_p[p];
        if (candidate > ans) ans = candidate;
    }

    return ans;
}
